import scala.collection.mutable.HashSet
import scala.collection.mutable.ArrayBuffer

def solve(s: String): Array[String] = {
   val segments = ArrayBuffer[String]()
   val seen = HashSet[String]()
   var current_index = 0
   while (current_index < s.length) {
       var current_segment = ""
       var added = false
       while (current_index < s.length && !added) {
           current_segment += s(current_index)
           if (!seen.contains(current_segment)) {
               seen.add(current_segment)
               segments += current_segment
               current_index += 1
               added = true
           } else {
               current_index += 1
           }
       }
   }
   segments.toArray
}
