def solve(s: String): Array[String] = {
    val segments = scala.collection.mutable.ArrayBuffer[String]()
    val used = scala.collection.mutable.HashSet[String]()
    var i = 0
    while (i < s.length) {
        var current = ""
        var j = i
        while (j < s.length) {
            current += s(j)
            if (!used.contains(current)) {
                used += current
                segments += current
                i = j + 1
                j = s.length // Break the inner loop
            } else {
                j += 1
            }
        }
    }
    segments.toArray
}
